function toggleMonthAccordion(key) {
    const targetContent = document.getElementById(`month-content-${key}`);
    const targetArrow = document.getElementById(`arrow-icon-${key}`);
    if (!targetContent || !targetArrow) return;

    const isCurrentlyClosed = targetContent.style.display === 'none';

    // Close all month contents and reset arrows
    document.querySelectorAll('[id^="month-content-"]').forEach(content => {
        content.style.display = 'none';
    });
    document.querySelectorAll('[id^="arrow-icon-"]').forEach(arrow => {
        arrow.style.transform = 'rotate(-90deg)';
    });

    // If the clicked one was closed, open it now
    if (isCurrentlyClosed) {
        targetContent.style.display = 'block';
        targetArrow.style.transform = 'rotate(0deg)';
    }
}

